parameters.query:
SELECT id, name, seller_username, config
FROM sources
WHERE platform = 'ebay' AND active = true;

parameters.jsCode:
// La Browse API exige al menos uno de: q, category_ids, epid, gtin o charity_ids.
// El filtro sellers: por sí solo devuelve error 12001, por eso q/category_ids
// se configuran por vendedor en sources.config.
const s = $json;
const cfg = s.config ?? {};

const params = new URLSearchParams();
if (cfg.q) params.set('q', cfg.q);
if (cfg.category_ids) params.set('category_ids', String(cfg.category_ids));
params.set('filter', `sellers:{${s.seller_username}}`);
params.set('limit', String(cfg.limit ?? 200));

return {
  json: {
    ...s,
    ebayUrl: `https://api.ebay.com/buy/browse/v1/item_summary/search?${params.toString()}`,
    marketplaceId: cfg.marketplace_id ?? 'EBAY_US',
  },
};

// Mapea la respuesta de la Browse API al esquema de products.
const source = $('Loop Over Sellers').first().json;
const out = [];

for (const item of $input.all()) {
  const s = item.json;
  const currency = s.price?.currency;

  // El esquema solo acepta PYG y USD. Si el marketplace configurado devuelve
  // otra moneda, salteamos el item en vez de guardar un precio con moneda falsa.
  if (currency !== 'USD' && currency !== 'PYG') continue;

  out.push({
    json: {
      source_id: source.id,
      external_id: s.itemId,
      name: s.title,
      description: s.shortDescription ?? null,
      category: s.categories?.[0]?.categoryName ?? null,
      price: s.price?.value != null ? Number(s.price.value) : null,
      currency,
      image_url: s.image?.imageUrl ?? null,
      product_url: s.itemWebUrl ?? null,
      seller_name: s.seller?.username ?? source.seller_username,
      location: s.itemLocation?.country ?? null,
    },
  });
}

return out;
